<div class="en">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
<text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">CRCLon/SPYon Issuance Structure vs. Offshore SPV Model</text>
<g font-family="sans-serif">
  <rect x="20" y="55" width="300" height="150" rx="10" fill="#1c1c1e" stroke="#71717a" stroke-width="1.2"/>
  <text x="40" y="80" fill="#a1a1aa" font-size="13" font-weight="700">Old: Offshore SPV wrapper</text>
  <text x="40" y="108" fill="#e4e4e7" font-size="12">SPV buys and holds real shares</text>
  <text x="40" y="130" fill="#e4e4e7" font-size="12">Token = contractual claim on SPV</text>
  <text x="40" y="152" fill="#f87171" font-size="12" font-weight="700">Not registered DTC ownership</text>
  <text x="40" y="176" fill="#f87171" font-size="12" font-weight="700">Mostly no redemption path</text>
  <rect x="380" y="55" width="300" height="150" rx="10" fill="#0e2a1e" stroke="#4ade80" stroke-width="1.2"/>
  <text x="400" y="80" fill="#86efac" font-size="13" font-weight="700">New: DTCC digital twin</text>
  <text x="400" y="108" fill="#e4e4e7" font-size="12">Underlying stays in DTC custody</text>
  <text x="400" y="130" fill="#e4e4e7" font-size="12">Token = 1:1 linked DTC entitlement</text>
